"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[835],{1286:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":" \\nCreates an Observer. Observers listen for entities subscribed Groups entering or exiting attached Zones.\\n\\n```lua\\nlocal observer = QuickZone.Observer.new({\\n\\tgroups = { enemyGroup, playerGroup } -- Immediately subscribe to these groups\\n\\tzones = { damageZone } -- Immediately subscribe to these zones\\n\\tpriority = 20, -- The priority value is used to resolve overlaps (defaults to 0)\\n\\tupdateRate = 20, -- Check at 20Hz (defaults to 30)\\n\\tprecision = 0.5, -- Ignore movement smaller than 0.5 studs (defaults to 0.1)\\n\\tenabled = false, -- Observer will not start processing spatial checks (defaults to true)\\n\\tsafety = false, -- Wrap callbacks in task.spawn (defaults to true)\\n})\\n```\\n\\n:::warning Safety \\nIf safety is set to false, any yielding will result in breaking QuickZone.\\nOnly set it to false if you do not want the overhead of virtual threads.\\n:::\\n\\n:::info Resolution Priority\\nWhen an entity is inside multiple zones watched by different observers, \\nhigher priority observers take complete control.\\n:::\\n\\n:::note Dynamic Instantiation\\nQuickZone will warn you if an Observer is created without groups or zones. \\nTo suppress this warning when building observers dynamically, \\nexplicitly pass an empty table (`zones = {}`) or instantiate the observer as disabled (`enabled = false`).\\n:::","params":[{"name":"config","desc":"","lua_type":"{ groups: { Types.Group }?, zones: { Types.Zone | Types.Zones }?, priority: number?, updateRate: number?, precision: number?, enabled: boolean?, safety: boolean? }?"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"static","tags":["Constructor","Chainable"],"source":{"line":151,"path":"src/Classes/Observer.luau"}},{"name":"subscribe","desc":" \\nLinks this observer to the specified group. The observer will only\\ntrack entities that belong to subscribed groups.\\n\\n```lua\\nobserver:subscribe(playerGroup):subscribe(enemyGroup)\\n```","params":[{"name":"group","desc":"The group to monitor.","lua_type":"Group"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":239,"path":"src/Classes/Observer.luau"}},{"name":"unsubscribe","desc":" \\nStops the observer from monitoring the specified group.","params":[{"name":"group","desc":"The group to stop monitoring.","lua_type":"Group"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":265,"path":"src/Classes/Observer.luau"}},{"name":"attach","desc":" \\nAttaches the Observer to a zone. The observer will begin \\nmonitoring this area for entity overlaps.\\n\\n```lua\\n-- You are also able to chain calls\\nobserver:attach(zone1)\\n\\t:attach(zone2)\\n\\t:attach(zone3)\\n```","params":[{"name":"zone","desc":"The zone to link.","lua_type":"Zone"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":294,"path":"src/Classes/Observer.luau"}},{"name":"detach","desc":" \\nDetaches the Observer from the zone. The observer will begin \\nmonitoring this area for entity overlaps.","params":[{"name":"zone","desc":"The zone to unlink.","lua_type":"Zone"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":310,"path":"src/Classes/Observer.luau"}},{"name":"observe","desc":" \\nObserves entities entering and exiting the zone. \\nThe callback executes on entry and expects a function to be returned, \\nwhich is executed on exit.\\n\\n```lua\\nobserver:observe(function(entity, zone)\\n\\tprint(\\"Entered\\", entity)\\n\\tlocal highlight = Instance.new(\\"Highlight\\", entity)\\n\\n\\t-- Return cleanup function\\n\\treturn function()\\n\\t\\tprint(\\"Exited\\", entity)\\n\\t\\thighlight:Destroy()\\n\\tend\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"(entity: any, zone: Zone) -> (() -> ())?"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","source":{"line":338,"path":"src/Classes/Observer.luau"}},{"name":"onEnter","desc":" \\nFires when any entity from a subscribed group enters a zone attached to this observer.\\n\\n```lua\\nlocal disconnect = observer:onEnter(function(entity, zone)\\n\\tprint(entity.Name .. \' entered \' .. zone.id)\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"(entity: any, zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":410,"path":"src/Classes/Observer.luau"}},{"name":"onExit","desc":" \\nFires when an entity exits all zones attached to this observer.","params":[{"name":"callback","desc":"","lua_type":"(entity: any, zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":429,"path":"src/Classes/Observer.luau"}},{"name":"observePlayer","desc":"Observes players entering and exiting the zone.\\n\\n```lua\\nobserver:observePlayer(function(player, zone)\\n\\tprint(player.Name .. \\" entered!\\")\\n\\t\\n\\t-- Return cleanup (optional)\\n\\treturn function()\\n\\t\\tprint(player.Name .. \\" left!\\")\\n\\tend\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"(player: Player, zone: Zone) -> (() -> ())?"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","source":{"line":458,"path":"src/Classes/Observer.luau"}},{"name":"onPlayerEnter","desc":" \\nSpecialized event for Player entities.\\n\\n```lua\\nobserver:onPlayerEnter(function(player, zone)\\n\\tprint(player.Name .. \\" entered safe zone \\" .. zone:getId())\\n\\t\\n\\t-- Play a sound\\n\\tlocal sound = workspace.Sounds.SafeZoneEnter:Clone()\\n\\tsound.Parent = player.Character.PrimaryPart\\n\\tsound:Play()\\n\\tgame.Debris:AddItem(sound, 2)\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"(player: Player, zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":544,"path":"src/Classes/Observer.luau"}},{"name":"onPlayerExit","desc":" \\nA specialized event for Player entities. Fires when a player\'s character \\nexits all zones attached to this observer.","params":[{"name":"callback","desc":"","lua_type":"(player: Player, zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":565,"path":"src/Classes/Observer.luau"}},{"name":"observeLocalPlayer","desc":"Observes the LocalPlayer.\\n\\n```lua\\nobserver:observeLocalPlayer(function(zone)\\n\\tlocal blur = Instance.new(\\"BlurEffect\\", game.Lighting)\\n\\treturn function()\\n\\t\\tblur:Destroy()\\n\\tend\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"(zone: Zone) -> (() -> ())?"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","realm":["Client"],"source":{"line":594,"path":"src/Classes/Observer.luau"}},{"name":"onLocalPlayerEnter","desc":" \\nSpecialized event for the LocalPlayer.\\n\\n```lua\\nobserver:onLocalPlayerEnter(function(zone)\\n\\tprint(\\"You entered zone \\" .. zone:getId())\\n\\t\\n\\tlocal char = player.Character\\n\\tif char and char:FindFirstChild(\\"Humanoid\\") then\\n\\t\\tchar.Humanoid.WalkSpeed = 24\\n\\tend\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"(zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"realm":["Client"],"source":{"line":684,"path":"src/Classes/Observer.luau"}},{"name":"onLocalPlayerExit","desc":" \\nA specialized event for the LocalPlayer. Fires when the local player\'s \\ncharacter exits all zones attached to this observer.","params":[{"name":"callback","desc":"","lua_type":"(zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"realm":["Client"],"source":{"line":707,"path":"src/Classes/Observer.luau"}},{"name":"observeGroup","desc":" \\nObserves a Group\'s presence within the observer\'s zones.\\nThe callback fires when the first entity of a group enters, and the \\nreturned cleanup function fires when the last entity of the group leaves.\\n\\n```lua\\nobserver:observeGroup(function(group, zone)\\n\\tprint(\\"Group \\" .. group:getId() .. \\" has arrived!\\")\\n\\treturn function()\\n\\t\\tprint(\\"Group \\" .. group:getId() .. \\" has left entirely.\\")\\n\\tend\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"(group: Group, zone: Zone) -> (() -> ())?"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","source":{"line":738,"path":"src/Classes/Observer.luau"}},{"name":"onGroupEnter","desc":" \\nFires when the first member of a Group enters any zone attached to this observer.\\nSubsequent entries by other members of the same group will not trigger this event\\nuntil the group has completely exited and re-entered.","params":[{"name":"callback","desc":"","lua_type":"(group: Group, zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":805,"path":"src/Classes/Observer.luau"}},{"name":"onGroupExit","desc":" \\nFires when the last remaining member of a Group exits all zones attached to \\nthis observer. This is useful for \\"cleared\\" states or stopping group-wide effects.","params":[{"name":"callback","desc":"","lua_type":"(group: Group, zone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":862,"path":"src/Classes/Observer.luau"}},{"name":"onTransition","desc":" \\nFires when an entity seamlessly transitions from one attached zone to another \\noverlapping attached zone.","params":[{"name":"callback","desc":"","lua_type":"(entity: any, newZone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":914,"path":"src/Classes/Observer.luau"}},{"name":"onPlayerTransition","desc":" \\nSpecialized event for Player entities transitioning between overlapping zones.\\nIf `targetPlayer` is provided, the event will only fire for that specific player.","params":[{"name":"callback","desc":"","lua_type":"(player: Player, newZone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":935,"path":"src/Classes/Observer.luau"}},{"name":"onLocalPlayerTransition","desc":" \\nSpecialized event for the LocalPlayer transitioning between overlapping zones.","params":[{"name":"callback","desc":"","lua_type":"(newZone: Zone) -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"realm":["Client"],"source":{"line":957,"path":"src/Classes/Observer.luau"}},{"name":"setEnabled","desc":" \\nEnables or disables the observer. When disabled, it will no longer process\\nspatial checks or fire events.","params":[{"name":"enabled","desc":"","lua_type":"boolean"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":983,"path":"src/Classes/Observer.luau"}},{"name":"setSafety","desc":"Whether to wrap callbacks in task.spawn (safe) or not (unsafe).\\n\\n:::warning Safety \\nIf set to unsafe, you are not allowed to yield in the callbacks anymore. If you do, QuickZone will throw errors.\\n:::","params":[{"name":"enabled","desc":"","lua_type":"boolean"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":1027,"path":"src/Classes/Observer.luau"}},{"name":"setPriority","desc":" \\nUpdates the resolution priority of the observer.","params":[{"name":"p","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":1041,"path":"src/Classes/Observer.luau"}},{"name":"setUpdateRate","desc":" \\nUpdates the update frequency for this observer.","params":[{"name":"hz","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":1056,"path":"src/Classes/Observer.luau"}},{"name":"setPrecision","desc":" \\nUpdates the precision in studs for this observer.","params":[{"name":"n","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Observer"}],"function_type":"method","tags":["Chainable"],"source":{"line":1075,"path":"src/Classes/Observer.luau"}},{"name":"isEnabled","desc":" \\nChecks if the observer is currently enabled.","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":1092,"path":"src/Classes/Observer.luau"}},{"name":"isPointInside","desc":" \\nChecks if a specific point in world space is inside any zone attached to this observer.","params":[{"name":"position","desc":"","lua_type":"Vector3"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":1104,"path":"src/Classes/Observer.luau"}},{"name":"isSafe","desc":" \\nChecks if the observer wraps callbacks in task.spawn (safe) or not (unsafe).","params":[],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":1176,"path":"src/Classes/Observer.luau"}},{"name":"getId","desc":" \\nReturns the unique internal ID of the observer.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":1187,"path":"src/Classes/Observer.luau"}},{"name":"getPriority","desc":" \\nReturns the current resolution priority.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":1198,"path":"src/Classes/Observer.luau"}},{"name":"getUpdateRate","desc":" \\nReturns the current update frequency for this observer.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":1209,"path":"src/Classes/Observer.luau"}},{"name":"getPrecision","desc":" \\nUpdates the precision for this observer.","params":[],"returns":[{"desc":"","lua_type":"number"}],"function_type":"method","source":{"line":1220,"path":"src/Classes/Observer.luau"}},{"name":"getEntitiesInside","desc":" \\nReturns a list of all tracked entities currently inside zones attached to this observer.","params":[],"returns":[{"desc":"","lua_type":"{ any }"}],"function_type":"method","source":{"line":1231,"path":"src/Classes/Observer.luau"}},{"name":"getPlayersInside","desc":" \\nReturns a list of all players currently inside zones attached to this observer.","params":[],"returns":[{"desc":"","lua_type":"{ Player }"}],"function_type":"method","source":{"line":1251,"path":"src/Classes/Observer.luau"}},{"name":"getZones","desc":" \\nReturns the list of Zones currently attached to this observer.","params":[],"returns":[{"desc":"","lua_type":"{ Zone }"}],"function_type":"method","source":{"line":1273,"path":"src/Classes/Observer.luau"}},{"name":"getGroups","desc":" \\nReturns the list of Groups currently monitored by this observer.","params":[],"returns":[{"desc":"","lua_type":"{ Group }"}],"function_type":"method","source":{"line":1295,"path":"src/Classes/Observer.luau"}},{"name":"getEntityInZone","desc":" \\nReturns the specific Zone this entity is currently tracked under for this Observer.","params":[{"name":"entity","desc":"The entity to get the zone for","lua_type":"Entity"}],"returns":[{"desc":"","lua_type":"Zone?"}],"function_type":"method","source":{"line":1320,"path":"src/Classes/Observer.luau"}},{"name":"getPlayerInZone","desc":" \\nReturns the specific Zone a player is currently tracked under for this Observer.","params":[{"name":"player","desc":"The player to get the zone for","lua_type":"Player"}],"returns":[{"desc":"","lua_type":"Zone?"}],"function_type":"method","source":{"line":1343,"path":"src/Classes/Observer.luau"}},{"name":"getEntitiesInZone","desc":" \\nReturns an array of all entities currently inside a specific zone attached to this observer.","params":[{"name":"zone","desc":"","lua_type":"Zone"}],"returns":[{"desc":"","lua_type":"{ any }"}],"function_type":"method","source":{"line":1355,"path":"src/Classes/Observer.luau"}},{"name":"getPlayersInZone","desc":" \\nReturns an array of all players currently inside a specific zone attached to this observer.","params":[{"name":"zone","desc":"","lua_type":"Zone"}],"returns":[{"desc":"","lua_type":"{ Player }"}],"function_type":"method","source":{"line":1373,"path":"src/Classes/Observer.luau"}},{"name":"iterZones","desc":" \\nReturns a zero-allocation iterator for all Zones currently attached to this observer.","params":[],"returns":[{"desc":"","lua_type":"() -> Zone?"}],"function_type":"method","source":{"line":1390,"path":"src/Classes/Observer.luau"}},{"name":"iterGroups","desc":" \\nReturns a zero-allocation iterator for all Groups currently monitored by this observer.","params":[],"returns":[{"desc":"","lua_type":"() -> Group?"}],"function_type":"method","source":{"line":1422,"path":"src/Classes/Observer.luau"}},{"name":"iterEntitiesInside","desc":" \\nIterates over all entities currently inside zones attached to this observer.\\nYields both the Entity and the specific Zone they are in.","params":[],"returns":[{"desc":"","lua_type":"() -> (Entity?, Zone?)"}],"function_type":"method","source":{"line":1455,"path":"src/Classes/Observer.luau"}},{"name":"iterPlayersInside","desc":" \\nIterates over all players currently inside zones attached to this observer.\\nYields both the Player and the specific Zone they are in.","params":[],"returns":[{"desc":"","lua_type":"() -> (Player?, Zone?)"}],"function_type":"method","source":{"line":1491,"path":"src/Classes/Observer.luau"}},{"name":"iterEntitiesInZone","desc":" \\nReturns a zero-allocation iterator for all entities currently inside a specific zone \\nattached to this observer.","params":[{"name":"zone","desc":"","lua_type":"Zone"}],"returns":[{"desc":"","lua_type":"() -> Entity?"}],"function_type":"method","source":{"line":1530,"path":"src/Classes/Observer.luau"}},{"name":"iterPlayersInZone","desc":" \\nReturns a zero-allocation iterator for all players currently inside a specific zone \\nattached to this observer.","params":[{"name":"zone","desc":"","lua_type":"Zone"}],"returns":[{"desc":"","lua_type":"() -> Player?"}],"function_type":"method","source":{"line":1569,"path":"src/Classes/Observer.luau"}},{"name":"onDestroy","desc":" \\nFires when `destroy()` is called on the observer\\n\\n```lua\\nlocal disconnect = myObserver:onDestroy(function()\\n\\tprint(\'Observer was destroyed!\')\\nend)\\n```","params":[{"name":"callback","desc":"","lua_type":"() -> ()"}],"returns":[{"desc":"Disconnect function","lua_type":"() -> ()"}],"function_type":"method","tags":["Event"],"source":{"line":1617,"path":"src/Classes/Observer.luau"}},{"name":"destroy","desc":" \\nCleans up the observer, disables tracking, and unsubscribes it from all groups and zones.","params":[],"returns":[],"function_type":"method","tags":["Destructor"],"source":{"line":1639,"path":"src/Classes/Observer.luau"}}],"properties":[],"types":[],"name":"Observer","desc":" \\n\\nObservers are the logical bridge between Groups and Zones.\\nThey monitor specific groups and trigger events when entities within those \\ngroups enter or exit any zones associated with the observer.","source":{"line":9,"path":"src/Classes/Observer.luau"}}')}}]);